#!/usr/bin/env bash
set -Eeuo pipefail

REPO="${ROUTEIQ_REPO:-/tmp/routeiq-v13}"
EXPECTED_BRANCH="${ROUTEIQ_EXPECTED_BRANCH:-track1-v13-ultra-local}"
EXPECTED_BASE="${ROUTEIQ_EXPECTED_BASE:-4785920}"
LOCAL_IMAGE="${ROUTEIQ_LOCAL_IMAGE:-routeiq-v13-ultra-local:test}"
PUBLISH="${ROUTEIQ_PUBLISH:-1}"
SKIP_DOCKER="${ROUTEIQ_SKIP_DOCKER:-0}"

say() { printf '\n==> %s\n' "$*"; }
die() { printf '\nERROR: %s\n' "$*" >&2; exit 1; }
trap 'printf "\nFAILED at line %s. The 100%% champion and portal submission were not touched.\n" "$LINENO" >&2' ERR

command -v git >/dev/null || die "git is required"
command -v python3 >/dev/null || die "python3 is required"
[[ -d "$REPO" ]] || die "worktree not found: $REPO"
cd "$REPO"
[[ "$(git rev-parse --is-inside-work-tree 2>/dev/null)" == "true" ]] || die "$REPO is not a git worktree"

BRANCH="$(git branch --show-current)"
[[ "$BRANCH" == "$EXPECTED_BRANCH" ]] || die "expected branch $EXPECTED_BRANCH, found $BRANCH"
git cat-file -e "${EXPECTED_BASE}^{commit}" 2>/dev/null || die "protected base commit $EXPECTED_BASE is unavailable"
git merge-base --is-ancestor "$EXPECTED_BASE" HEAD || die "current branch is not descended from protected champion $EXPECTED_BASE"
git diff --quiet || die "tracked working-tree changes exist; commit or stash them first"
git diff --cached --quiet || die "staged changes exist; commit or unstage them first"

say "Installing isolated v1.3 candidate files"
STAMP="$(date +%Y%m%d-%H%M%S)"
if [[ -e track1-v13-agent ]]; then
  tar -czf "/tmp/routeiq-v13-backup-${STAMP}.tgz" track1-v13-agent
  rm -rf track1-v13-agent
fi
PAYLOAD_FILE="$(mktemp)"
base64 -d > "$PAYLOAD_FILE" <<'ROUTEIQ_PAYLOAD'

ROUTEIQ_PAYLOAD
tar -xzf "$PAYLOAD_FILE" -C "$REPO"
rm -f "$PAYLOAD_FILE"

if [[ -n "$(git diff --name-only -- track1-v12-agent)" ]]; then
  die "protected champion folder was modified"
fi

say "Running Python unit and routing tests"
(
  cd track1-v13-agent
  python3 -m unittest discover -s tests -v
)

if [[ "$SKIP_DOCKER" == "1" ]]; then
  say "Docker stage skipped by ROUTEIQ_SKIP_DOCKER=1"
  exit 0
fi

command -v docker >/dev/null || die "docker is required"
docker info >/dev/null 2>&1 || die "Docker daemon is unavailable"
command -v timeout >/dev/null || die "GNU timeout is required"

say "Building isolated local candidate image"
docker build --progress=plain -t "$LOCAL_IMAGE" track1-v13-agent

BENCH_ROOT="$(mktemp -d)"
mkdir -p "$BENCH_ROOT/input" "$BENCH_ROOT/output"
chmod 777 "$BENCH_ROOT/output"
cp track1-v13-agent/bench/tasks.json "$BENCH_ROOT/input/tasks.json"

say "Running 19-task judge-style benchmark under 2 CPU / 4 GB"
START_SECONDS="$(date +%s)"
set +e
timeout 540 docker run --rm \
  --network none \
  --cpus=2 \
  --memory=4g \
  -e ROUTEIQ_LOCAL_ONLY=1 \
  -v "$BENCH_ROOT/input:/input:ro" \
  -v "$BENCH_ROOT/output:/output" \
  "$LOCAL_IMAGE" 2>&1 | tee "$BENCH_ROOT/container.log"
RUN_STATUS="${PIPESTATUS[0]}"
set -e
END_SECONDS="$(date +%s)"
printf '%s\n' "$((END_SECONDS - START_SECONDS))" > "$BENCH_ROOT/runtime.txt"

if [[ "$RUN_STATUS" -ne 0 ]]; then
  die "candidate container failed or exceeded 540 seconds; logs: $BENCH_ROOT/container.log"
fi
[[ -s "$BENCH_ROOT/output/results.json" ]] || die "candidate did not create results.json"

python3 track1-v13-agent/bench/score_benchmark.py \
  "$BENCH_ROOT/input/tasks.json" \
  "$BENCH_ROOT/output/results.json" \
  "$BENCH_ROOT/runtime.txt"

ARCH="$(docker image inspect --format '{{.Architecture}}' "$LOCAL_IMAGE")"
SIZE="$(docker image inspect --format '{{.Size}}' "$LOCAL_IMAGE")"
[[ "$ARCH" == "amd64" ]] || die "candidate architecture is $ARCH, not amd64"
[[ "$SIZE" -lt 8000000000 ]] || die "candidate uncompressed image size is unexpectedly high: $SIZE bytes"

say "Saving the candidate code locally without pushing source"
find track1-v13-agent -type d -name __pycache__ -prune -exec rm -rf {} +
find track1-v13-agent -type f -name '*.pyc' -delete
git add track1-v13-agent
if ! git diff --cached --quiet; then
  git commit -m "feat(track1): add v1.3 ultra-local guarded candidate"
fi
COMMIT="$(git rev-parse HEAD)"
REPORT="$BENCH_ROOT/output/benchmark-report.json"

if [[ "$PUBLISH" != "1" ]]; then
  say "Benchmark passed; publication skipped by ROUTEIQ_PUBLISH=$PUBLISH"
  printf 'Candidate commit: %s\nBenchmark report: %s\n' "$COMMIT" "$REPORT"
  exit 0
fi

command -v gh >/dev/null || die "GitHub CLI is required for private candidate publication"
OWNER="$(gh repo view --json owner --jq '.owner.login')"
[[ -n "$OWNER" ]] || die "could not determine GitHub repository owner"
TOKEN="$(gh auth token)"
[[ -n "$TOKEN" ]] || die "GitHub CLI is not authenticated"
OPAQUE="$(python3 - <<'PYOPAQUE'
import secrets
print(secrets.token_hex(6))
PYOPAQUE
)"
REMOTE_IMAGE="ghcr.io/${OWNER,,}/omniedge-routeiq-track1:c-${OPAQUE}"

say "Publishing an opaque candidate tag to the existing GHCR package"
printf '%s' "$TOKEN" | docker login ghcr.io -u "$OWNER" --password-stdin >/dev/null
docker tag "$LOCAL_IMAGE" "$REMOTE_IMAGE"
docker push "$REMOTE_IMAGE"

DIGEST="$(docker image inspect --format '{{join .RepoDigests "\n"}}' "$REMOTE_IMAGE" | head -n1 || true)"
PRIVATE_FILE="/tmp/routeiq-v13-private-candidate.txt"
{
  printf 'PRIVATE — DO NOT POST IN DISCORD OR README\n'
  printf 'image=%s\n' "$REMOTE_IMAGE"
  printf 'digest=%s\n' "$DIGEST"
  printf 'commit=%s\n' "$COMMIT"
  printf 'benchmark_report=%s\n' "$REPORT"
  printf 'benchmark_results=%s\n' "$BENCH_ROOT/output/results.json"
  printf 'container_log=%s\n' "$BENCH_ROOT/container.log"
} > "$PRIVATE_FILE"
chmod 600 "$PRIVATE_FILE"

say "Verifying that judges can pull the candidate without registry authentication"
docker logout ghcr.io >/dev/null 2>&1 || true
docker pull "$REMOTE_IMAGE" >/dev/null
PULLED_ARCH="$(docker image inspect --format '{{.Architecture}}' "$REMOTE_IMAGE")"
[[ "$PULLED_ARCH" == "amd64" ]] || die "published candidate is not linux/amd64"

say "V1.3 candidate passed all guarded gates"
printf 'Private candidate details: %s\n' "$PRIVATE_FILE"
printf 'Benchmark report: %s\n' "$REPORT"
printf 'Source branch was NOT pushed. Portal submission was NOT changed.\n'
